import time
import random
import functools

class TransientError(Exception): pass
class RecoverableError(Exception): pass
class FatalError(Exception): pass


def backoff_delay(attempt: int, base: float = 1.0, cap: float = 60.0) -> float:
    """Exponential backoff with full jitter."""
    delay = min(cap, base * (2 ** attempt))
    return delay * random.uniform(0.5, 1.5)


def with_retry(
    max_attempts: int = 5,
    transient_types: tuple = (TransientError,),
    deadline: float | None = None,
):
    """Decorator: retry transient errors with exponential backoff + jitter."""
    def decorator(fn):
        @functools.wraps(fn)
        def wrapper(*args, **kwargs):
            start = time.monotonic()
            for attempt in range(max_attempts):
                try:
                    return fn(*args, **kwargs)
                except transient_types as exc:
                    if attempt == max_attempts - 1:
                        raise  # exhausted — let caller handle
                    elapsed = time.monotonic() - start
                    if deadline and elapsed >= deadline:
                        raise TimeoutError(
                            f"retry deadline exceeded after {elapsed:.1f}s"
                        ) from exc
                    delay = backoff_delay(attempt)
                    # Respect Retry-After header if present
                    if hasattr(exc, "retry_after"):
                        delay = max(delay, exc.retry_after)
                    time.sleep(delay)
        return wrapper
    return decorator

import json
import time
import random
import anthropic

primary = anthropic.Anthropic()

def backoff(n: int, cap: float = 30.0) -> None:
    time.sleep(min(cap, 1.0 * 2**n) * random.uniform(0.5, 1.5))

# ── tool implementations ───────────────────────────────────────────────────
def search_web(query: str) -> dict:
    # Imagine a real search client here.
    return {"results": [f"result for: {query}"]}

TOOLS = {
    "search_web": search_web,
}

TOOL_SCHEMAS = [
    {
        "name": "search_web",
        "description": "Search the web for up-to-date information.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    }
]

# ── retry-aware LLM call ───────────────────────────────────────────────────
TRANSIENT = (anthropic.RateLimitError, anthropic.InternalServerError)

def llm_call(messages: list, model: str, max_attempts: int = 4) -> anthropic.types.Message:
    for attempt in range(max_attempts):
        try:
            return primary.messages.create(
                model=model,
                max_tokens=2048,
                tools=TOOL_SCHEMAS,
                messages=messages,
            )
        except TRANSIENT as exc:
            if attempt == max_attempts - 1:
                raise
            backoff(attempt)
        except anthropic.APIStatusError as exc:
            raise  # 4xx → fatal, don't retry

# ── resilient agent loop ──────────────────────────────────────────────────
def run_agent(task: str, model: str = "claude-opus-4-5", fallback_model: str = "claude-haiku-4-5") -> str:
    messages = [{"role": "user", "content": task}]
    checkpoint = []          # durable state

    for turn in range(20):   # hard turn limit
        # try primary, fall back to cheaper model on exhausted retries
        try:
            response = llm_call(messages, model)
        except TRANSIENT:
            print(f"Primary model unavailable, switching to {fallback_model}")
            response = llm_call(messages, fallback_model)

        # append assistant message
        messages.append({"role": "assistant", "content": response.content})
        checkpoint.append({"turn": turn, "messages": messages.copy()})  # checkpoint

        if response.stop_reason == "end_turn":
            return response.content[0].text

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    tool_fn = TOOLS.get(block.name)
                    if tool_fn is None:
                        result = {"error": f"unknown tool: {block.name}"}
                    else:
                        try:
                            result = tool_fn(**block.input)
                        except Exception as exc:
                            # Return structured error so model can replan
                            result = {"error": str(exc), "tool": block.name}
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": json.dumps(result),
                    })
            messages.append({"role": "user", "content": tool_results})

    return "Agent hit turn limit without completing task."


if __name__ == "__main__":
    answer = run_agent("What are the three main backoff strategies used in distributed systems?")
    print(answer)

import json
import boto3

s3 = boto3.client("s3")
BUCKET = "contracts-checkpoints"

def save_checkpoint(contract_id: str, state: dict) -> None:
    key = f"checkpoints/{contract_id}.json"
    s3.put_object(
        Bucket=BUCKET,
        Key=key,
        Body=json.dumps(state),
        ContentType="application/json",
    )

def load_checkpoint(contract_id: str) -> dict | None:
    key = f"checkpoints/{contract_id}.json"
    try:
        obj = s3.get_object(Bucket=BUCKET, Key=key)
        return json.loads(obj["Body"].read())
    except s3.exceptions.NoSuchKey:
        return None

def process_contract(contract_id: str, chunks: list[str]) -> dict:
    checkpoint = load_checkpoint(contract_id) or {"next_chunk": 0, "fields": {}}
    start = checkpoint["next_chunk"]

    for i, chunk in enumerate(chunks[start:], start=start):
        fields = extract_fields_with_retry(chunk)  # retry-wrapped LLM call
        checkpoint["fields"].update(fields)
        checkpoint["next_chunk"] = i + 1

        if (i + 1) % 10 == 0:
            save_checkpoint(contract_id, checkpoint)  # durable save every 10 chunks

    save_checkpoint(contract_id, checkpoint)  # final save
    return checkpoint["fields"]

